import React, { useState } from 'react';
import { Carousel } from 'react-bootstrap';
import CollapsedText from './CollapsedText';

function SimpleCarousel({ images }) {
    const [showDetails, setShowDetails] = useState(true);
    const isSmallScreen = window.innerWidth < 768; // Define el ancho de pantalla para ocultar los elementos

    return (
        <Carousel data-bs-theme="dark" indicators={!isSmallScreen}>
            {images.map((image, index) => (
                <Carousel.Item key={index} className='carouselItem'>
                    <img
                        className="d-block w-100"
                        src={image.src}
                        alt={image.title}
                    />
                    {isSmallScreen && !showDetails && ( // Muestra el CollapsedText solo en pantallas pequeñas y cuando los detalles no están visibles
                        <CollapsedText
                            name={image.title}
                            text={image.description}
                            maxLines={3}
                        />
                    )}
                    <Carousel.Caption className={isSmallScreen || showDetails ? 'd-none' : ''}>
                        <h5>{image.title}</h5>
                        <p>{image.description}</p>
                        {/* Aquí coloca los botones */}
                    </Carousel.Caption>
                </Carousel.Item>
            ))}
        </Carousel>
    );
}

export default SimpleCarousel;
